import os
from flask import Flask, request, jsonify
from datetime import datetime, timedelta
import pickle
import json
import hashlib

app = Flask(__name__)

# Cache directory and file name
CACHE_DIR = 'cache'
CACHE_FILE = 'api_responses.pkl'

def cache_response(response):
    """Serialize response data to disk."""
    with open(os.path.join(CACHE_DIR, CACHE_FILE), 'wb') as f:
        pickle.dump(response, f)

def load_cached_response():
    """Reload cached response from disk."""
    try:
        with open(os.path.join(CACHE_DIR, CACHE_FILE), 'rb') as f:
            return pickle.load(f)
    except FileNotFoundError:
        return None

def is_cache_expired(timestamp):
    """Check if cache has expired based on timestamp."""
    expiration_time = datetime.now() - timedelta(hours=1)  # Cache expires after 1 hour
    return timestamp < expiration_time.timestamp()

